#include <stdio.h>
#include <string.h>
#include <stdbool.h>
static const bool primeSum[18]={false,false,true,true,false,true,false,true,false,false,false,true,false,true,false,false,false,true};
static const int neigh[9][4]={{1,3,-1,-1},{0,2,4,-1},{1,5,-1,-1},{0,4,6,-1},{1,3,5,7},{2,4,8,-1},{3,7,-1,-1},{4,6,8,-1},{5,7,-1,-1}};
int factorial[10];
int encode(int *a){int used[10]={0};int idx=0;for(int i=0;i<9;i++){int cnt=0;for(int v=1;v<a[i];v++)if(!used[v])cnt++;idx+=cnt*factorial[8-i];used[a[i]]=1;}return idx;}
void decode(int idx,int *a){int pool[9];for(int i=0;i<9;i++)pool[i]=i+1;for(int i=0;i<9;i++){int f=factorial[8-i];int pos=idx/f;idx%=f;a[i]=pool[pos];for(int j=pos;j<8-i;j++)pool[j]=pool[j+1];}}
int main(){factorial[0]=1;for(int i=1;i<=9;i++)factorial[i]=factorial[i-1]*i;int T;if(scanf("%d",&T)!=1)return 0;while(T--){int start[9];for(int i=0;i<9;i++)scanf("%d",&start[i]);int startIdx=encode(start);int goal[9]={1,2,3,4,5,6,7,8,9};int goalIdx=encode(goal);static bool visited[362880];static int dist[362880];memset(visited,0,sizeof(visited));int q[362880];int head=0,tail=0;visited[startIdx]=true;dist[startIdx]=0;q[tail++]=startIdx;int answer=-1;int cur[9];while(head<tail){int curIdx=q[head++];if(curIdx==goalIdx){answer=dist[curIdx];break;}decode(curIdx,cur);for(int i=0;i<9;i++){for(int k=0;k<4;k++){int j=neigh[i][k];if(j==-1)break;int sum=cur[i]+cur[j];if(!primeSum[sum])continue;int tmp=cur[i];cur[i]=cur[j];cur[j]=tmp;int nxtIdx=encode(cur);if(!visited[nxtIdx]){visited[nxtIdx]=true;dist[nxtIdx]=dist[curIdx]+1;q[tail++]=nxtIdx;}tmp=cur[i];cur[i]=cur[j];cur[j]=tmp;}}}
printf("%d\n",answer);}return 0;
